from __future__ import annotations

import asyncio


async def collect_cursor_items(fetch_page, *, start_cursor=None, per_page_timeout=None):
    out = []
    cursor = start_cursor
    while True:
        if per_page_timeout is None:
            items, cursor = await fetch_page(cursor)
        else:
            items, cursor = await asyncio.wait_for(fetch_page(cursor), timeout=per_page_timeout)
        out.extend(items)
        if cursor is None:
            return out

