import asyncio

from solution import collect_cursor_items


def test_collects_all_pages():
    async def fetch(cursor):
        pages = {
            None: ([1, 2], 'b'),
            'b': ([3], None),
        }
        return pages[cursor]

    assert asyncio.run(collect_cursor_items(fetch)) == [1, 2, 3]
